1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const blockOfThreeDiscount = (count: number): number =>
41	  count === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
42	
43	const calculateBasePremium = (items: Item[]): number => {
44	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
45	  const runeCount = items.filter((item) => item.type === "rune").length;
46	  return subtotal - blockOfThreeDiscount(runeCount);
47	};
48	
49	const quote = (step: QuoteStep): QuoteResult => {
50	  const basePremium = calculateBasePremium(step.items);
51	  const firstContractSurcharge = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
52	  const premium = Math.ceil(basePremium + firstContractSurcharge + PROCESSING_FEE);
53	  return { premium };
54	};
55	
56	export const runScenario = (scenario: Scenario): ScenarioResult => {
57	  const results = scenario.steps.map(quote);
58	  return { results };
59	};
